/*
 * iolib.c - Yalnix File System Client Library
 *
 * Each function packages arguments into a 32-byte message, sends it to
 * the YFS server, and returns the result from the reply.
 *
 * NOTE: Do NOT use printf/fprintf here -- output appears in TTYLOG.
 */

#include <comp421/filesystem.h>
#include <comp421/yalnix.h>
#include <comp421/iolib.h>
#include <string.h>

#include "yfs.h"

/* ------------------------------------------------------------------ */
/* File descriptor table                                                */
/* ------------------------------------------------------------------ */

struct fd_slot {
    int in_use;
    int inum;
    int reuse;
    int pos;
};

static struct fd_slot fd_table[MAX_OPEN_FILES];
static int cwd_inum    = ROOTINODE;
static int initialized = 0;

static void lib_init(void) {
    int i;
    if (initialized) return;
    for (i = 0; i < MAX_OPEN_FILES; i++) fd_table[i].in_use = 0;
    cwd_inum    = ROOTINODE;
    initialized = 1;
}

static int alloc_fd(void) {
    int i;
    for (i = 0; i < MAX_OPEN_FILES; i++)
        if (!fd_table[i].in_use) return i;
    return -1;
}

static int valid_fd(int fd) {
    return fd >= 0 && fd < MAX_OPEN_FILES && fd_table[fd].in_use;
}

/* ------------------------------------------------------------------ */
/* Send a message and receive the reply (in the same buffer).          */
/* Returns the reply's ret field, or ERROR.                            */
/* ------------------------------------------------------------------ */

static int do_send(void *msg) {
    struct msg_reply *r = (struct msg_reply *)msg;
    if (Send(msg, -FILE_SERVER) == ERROR) return ERROR;
    return r->ret;
}

/* ================================================================== */
/* Open                                                                 */
/* ================================================================== */

int Open(char *pathname) {
    struct msg_path msg;
    struct msg_reply *r = (struct msg_reply *)&msg;
    int fd, pathlen;

    lib_init();
    if (!pathname) return ERROR;
    pathlen = (int)strlen(pathname) + 1;
    if (pathlen > MAXPATHNAMELEN) return ERROR;

    fd = alloc_fd();
    if (fd < 0) return ERROR;

    msg.type     = MSG_OPEN;
    msg.cwd_inum = cwd_inum;
    msg.pathlen  = pathlen;
    msg.pathlen2 = 0;
    msg.path     = pathname;
    msg.path2    = NULL;

    if (do_send(&msg) == ERROR) return ERROR;

    fd_table[fd].in_use = 1;
    fd_table[fd].inum   = r->inum;
    fd_table[fd].reuse  = r->reuse;
    fd_table[fd].pos    = 0;
    return fd;
}

/* ================================================================== */
/* Close                                                                */
/* ================================================================== */

int Close(int fd) {
    lib_init();
    if (!valid_fd(fd)) return ERROR;
    fd_table[fd].in_use = 0;
    return 0;
}

/* ================================================================== */
/* Create                                                               */
/* ================================================================== */

int Create(char *pathname) {
    struct msg_path msg;
    struct msg_reply *r = (struct msg_reply *)&msg;
    int fd, pathlen;

    lib_init();
    if (!pathname) return ERROR;
    pathlen = (int)strlen(pathname) + 1;
    if (pathlen > MAXPATHNAMELEN) return ERROR;

    fd = alloc_fd();
    if (fd < 0) return ERROR;

    msg.type     = MSG_CREATE;
    msg.cwd_inum = cwd_inum;
    msg.pathlen  = pathlen;
    msg.pathlen2 = 0;
    msg.path     = pathname;
    msg.path2    = NULL;

    if (do_send(&msg) == ERROR) return ERROR;

    fd_table[fd].in_use = 1;
    fd_table[fd].inum   = r->inum;
    fd_table[fd].reuse  = r->reuse;
    fd_table[fd].pos    = 0;
    return fd;
}

/* ================================================================== */
/* Read                                                                 */
/* ================================================================== */

int Read(int fd, void *buf, int size) {
    struct msg_rw msg;
    int ret;

    lib_init();
    if (!valid_fd(fd)) return ERROR;
    if (size < 0)  return ERROR;
    if (size == 0) return 0;

    msg.type  = MSG_READ;
    msg.inum  = fd_table[fd].inum;
    msg.reuse = fd_table[fd].reuse;
    msg.pos   = fd_table[fd].pos;
    msg.buf   = buf;
    msg.size  = size;
    msg.pad   = 0;

    ret = do_send(&msg);
    if (ret == ERROR) return ERROR;
    fd_table[fd].pos += ret;
    return ret;
}

/* ================================================================== */
/* Write                                                                */
/* ================================================================== */

int Write(int fd, void *buf, int size) {
    struct msg_rw msg;
    int ret;

    lib_init();
    if (!valid_fd(fd)) return ERROR;
    if (size < 0)  return ERROR;
    if (size == 0) return 0;

    msg.type  = MSG_WRITE;
    msg.inum  = fd_table[fd].inum;
    msg.reuse = fd_table[fd].reuse;
    msg.pos   = fd_table[fd].pos;
    msg.buf   = buf;
    msg.size  = size;
    msg.pad   = 0;

    ret = do_send(&msg);
    if (ret == ERROR) return ERROR;
    fd_table[fd].pos += ret;
    return ret;
}

/* ================================================================== */
/* Seek                                                                 */
/* ================================================================== */

int Seek(int fd, int offset, int whence) {
    struct msg_seek msg;
    int new_pos;

    lib_init();
    if (!valid_fd(fd)) return ERROR;

    msg.type   = MSG_SEEK;
    msg.inum   = fd_table[fd].inum;
    msg.reuse  = fd_table[fd].reuse;
    msg.pos    = fd_table[fd].pos;
    msg.offset = offset;
    msg.whence = whence;
    memset(msg.pad, 0, sizeof(msg.pad));

    new_pos = do_send(&msg);
    if (new_pos == ERROR) return ERROR;
    fd_table[fd].pos = new_pos;
    return new_pos;
}

/* ================================================================== */
/* Link                                                                 */
/* ================================================================== */

int Link(char *oldname, char *newname) {
    struct msg_path msg;
    int oldlen, newlen;

    lib_init();
    if (!oldname || !newname) return ERROR;
    oldlen = (int)strlen(oldname) + 1;
    newlen = (int)strlen(newname) + 1;
    if (oldlen > MAXPATHNAMELEN || newlen > MAXPATHNAMELEN) return ERROR;

    msg.type     = MSG_LINK;
    msg.cwd_inum = cwd_inum;
    msg.pathlen  = oldlen;
    msg.pathlen2 = newlen;
    msg.path     = oldname;
    msg.path2    = newname;

    return do_send(&msg);
}

/* ================================================================== */
/* Unlink                                                               */
/* ================================================================== */

int Unlink(char *pathname) {
    struct msg_path msg;
    int pathlen;

    lib_init();
    if (!pathname) return ERROR;
    pathlen = (int)strlen(pathname) + 1;
    if (pathlen > MAXPATHNAMELEN) return ERROR;

    msg.type     = MSG_UNLINK;
    msg.cwd_inum = cwd_inum;
    msg.pathlen  = pathlen;
    msg.pathlen2 = 0;
    msg.path     = pathname;
    msg.path2    = NULL;

    return do_send(&msg);
}

/* ================================================================== */
/* SymLink                                                              */
/* ================================================================== */

int SymLink(char *oldname, char *newname) {
    struct msg_path msg;
    int oldlen, newlen;

    lib_init();
    if (!oldname || !newname) return ERROR;
    oldlen = (int)strlen(oldname) + 1;
    newlen = (int)strlen(newname) + 1;
    if (oldlen > MAXPATHNAMELEN || newlen > MAXPATHNAMELEN) return ERROR;

    msg.type     = MSG_SYMLINK;
    msg.cwd_inum = cwd_inum;
    msg.pathlen  = oldlen;
    msg.pathlen2 = newlen;
    msg.path     = oldname;
    msg.path2    = newname;

    return do_send(&msg);
}

/* ================================================================== */
/* ReadLink                                                             */
/* ================================================================== */

int ReadLink(char *pathname, char *buf, int len) {
    struct msg_path msg;
    int pathlen;

    lib_init();
    if (!pathname || !buf) return ERROR;
    pathlen = (int)strlen(pathname) + 1;
    if (pathlen > MAXPATHNAMELEN) return ERROR;

    msg.type     = MSG_READLINK;
    msg.cwd_inum = cwd_inum;
    msg.pathlen  = pathlen;
    msg.pathlen2 = len;
    msg.path     = pathname;
    msg.path2    = buf;

    return do_send(&msg);
}

/* ================================================================== */
/* MkDir                                                                */
/* ================================================================== */

int MkDir(char *pathname) {
    struct msg_path msg;
    int pathlen;

    lib_init();
    if (!pathname) return ERROR;
    pathlen = (int)strlen(pathname) + 1;
    if (pathlen > MAXPATHNAMELEN) return ERROR;

    msg.type     = MSG_MKDIR;
    msg.cwd_inum = cwd_inum;
    msg.pathlen  = pathlen;
    msg.pathlen2 = 0;
    msg.path     = pathname;
    msg.path2    = NULL;

    return do_send(&msg);
}

/* ================================================================== */
/* RmDir                                                                */
/* ================================================================== */

int RmDir(char *pathname) {
    struct msg_path msg;
    int pathlen;

    lib_init();
    if (!pathname) return ERROR;
    pathlen = (int)strlen(pathname) + 1;
    if (pathlen > MAXPATHNAMELEN) return ERROR;

    msg.type     = MSG_RMDIR;
    msg.cwd_inum = cwd_inum;
    msg.pathlen  = pathlen;
    msg.pathlen2 = 0;
    msg.path     = pathname;
    msg.path2    = NULL;

    return do_send(&msg);
}

/* ================================================================== */
/* ChDir                                                                */
/* ================================================================== */

int ChDir(char *pathname) {
    struct msg_path msg;
    struct msg_reply *r = (struct msg_reply *)&msg;
    int pathlen, ret;

    lib_init();
    if (!pathname) return ERROR;
    pathlen = (int)strlen(pathname) + 1;
    if (pathlen > MAXPATHNAMELEN) return ERROR;

    msg.type     = MSG_CHDIR;
    msg.cwd_inum = cwd_inum;
    msg.pathlen  = pathlen;
    msg.pathlen2 = 0;
    msg.path     = pathname;
    msg.path2    = NULL;

    ret = do_send(&msg);
    if (ret == ERROR) return ERROR;
    cwd_inum = r->inum;
    return 0;
}

/* ================================================================== */
/* Stat                                                                 */
/* ================================================================== */

int Stat(char *pathname, struct Stat *statbuf) {
    struct msg_path msg;
    int pathlen;

    lib_init();
    if (!pathname || !statbuf) return ERROR;
    pathlen = (int)strlen(pathname) + 1;
    if (pathlen > MAXPATHNAMELEN) return ERROR;

    msg.type     = MSG_STAT;
    msg.cwd_inum = cwd_inum;
    msg.pathlen  = pathlen;
    msg.pathlen2 = 0;
    msg.path     = pathname;
    msg.path2    = statbuf;  /* server uses CopyTo to fill this */

    return do_send(&msg);
}

/* ================================================================== */
/* Sync                                                                 */
/* ================================================================== */

int Sync(void) {
    struct msg_simple msg;

    lib_init();
    msg.type = MSG_SYNC;
    memset(msg.pad, 0, sizeof(msg.pad));

    return do_send(&msg);
}

/* ================================================================== */
/* Shutdown                                                             */
/* ================================================================== */

int Shutdown(void) {
    struct msg_simple msg;

    lib_init();
    msg.type = MSG_SHUTDOWN;
    memset(msg.pad, 0, sizeof(msg.pad));

    return do_send(&msg);
}

/*
 * yfs.c - Yalnix File System Server
 */

#include <comp421/filesystem.h>
#include <comp421/yalnix.h>
#include <string.h>
#include <stdlib.h>

#include "yfs.h"

/* ------------------------------------------------------------------ */
/* Constants                                                            */
/* ------------------------------------------------------------------ */

#define INODES_PER_BLOCK  (BLOCKSIZE / INODESIZE)   /* 8 */
#define DIRENTS_PER_BLOCK (BLOCKSIZE / sizeof(struct dir_entry)) /* 16 */
#define INDIR_ENTRIES     (BLOCKSIZE / (int)sizeof(int))  /* 128 */

#define MAX_INODE_NUM  512
#define MAX_BLOCK_NUM  2048

/*
 * lookup_path return values:
 *   > 0        : found, inode number
 *   NOT_FOUND  : last component absent, parent_inum set correctly
 *   ERROR (-1) : path error (bad path, intermediate missing, etc.)
 */
#define NOT_FOUND (-2)

/* Stat struct (mirrors comp421/iolib.h) */
struct Stat {
    int inum;
    int type;
    int size;
    int nlink;
};

/* ------------------------------------------------------------------ */
/* Global FS parameters (read from superblock)                         */
/* ------------------------------------------------------------------ */

static int g_num_inodes;
static int g_num_blocks;
static int g_first_data_block;

/* ------------------------------------------------------------------ */
/* Free lists                                                           */
/* ------------------------------------------------------------------ */

static int free_inodes[MAX_INODE_NUM];
static int free_inode_cnt;

static int free_blocks[MAX_BLOCK_NUM];
static int free_block_cnt;

/* ------------------------------------------------------------------ */
/* Block cache (LRU, write-back, BLOCK_CACHESIZE entries)              */
/* ------------------------------------------------------------------ */

struct blk_entry {
    int  block_num;   /* -1 = unused slot */
    int  dirty;
    struct blk_entry *lru_prev;
    struct blk_entry *lru_next;
    char data[BLOCKSIZE];
};

static struct blk_entry blk_cache[BLOCK_CACHESIZE];
static struct blk_entry *blk_lru_head;  /* MRU end */
static struct blk_entry *blk_lru_tail;  /* LRU end */

/* ------------------------------------------------------------------ */
/* Inode cache (LRU, write-back, INODE_CACHESIZE entries)              */
/* ------------------------------------------------------------------ */

struct ino_entry {
    int  inum;   /* -1 = unused slot */
    int  dirty;
    struct ino_entry *lru_prev;
    struct ino_entry *lru_next;
    struct inode inode;
};

static struct ino_entry ino_cache[INODE_CACHESIZE];
static struct ino_entry *ino_lru_head;
static struct ino_entry *ino_lru_tail;

/* ================================================================== */
/* Block cache helpers                                                  */
/* ================================================================== */

static void blk_lru_remove(struct blk_entry *e) {
    if (e->lru_prev) e->lru_prev->lru_next = e->lru_next;
    else             blk_lru_head = e->lru_next;
    if (e->lru_next) e->lru_next->lru_prev = e->lru_prev;
    else             blk_lru_tail = e->lru_prev;
    e->lru_prev = e->lru_next = NULL;
}

static void blk_lru_push_front(struct blk_entry *e) {
    e->lru_prev = NULL;
    e->lru_next = blk_lru_head;
    if (blk_lru_head) blk_lru_head->lru_prev = e;
    else              blk_lru_tail = e;
    blk_lru_head = e;
}

static void blk_lru_move_front(struct blk_entry *e) {
    if (e != blk_lru_head) {
        blk_lru_remove(e);
        blk_lru_push_front(e);
    }
}

static struct blk_entry *blk_find(int block_num) {
    int i;
    for (i = 0; i < BLOCK_CACHESIZE; i++)
        if (blk_cache[i].block_num == block_num)
            return &blk_cache[i];
    return NULL;
}

static struct blk_entry *blk_evict(void) {
    struct blk_entry *e = blk_lru_tail;
    if (!e) return NULL;
    if (e->dirty) {
        WriteSector(e->block_num, e->data);
        e->dirty = 0;
    }
    blk_lru_remove(e);
    e->block_num = -1;
    return e;
}

static struct blk_entry *blk_free_slot(void) {
    int i;
    for (i = 0; i < BLOCK_CACHESIZE; i++)
        if (blk_cache[i].block_num == -1)
            return &blk_cache[i];
    return blk_evict();
}

/* Returns pointer to block data (or NULL on error). */
static char *get_block(int bnum) {
    struct blk_entry *e;
    if (bnum <= 0) return NULL;
    e = blk_find(bnum);
    if (e) { blk_lru_move_front(e); return e->data; }

    e = blk_free_slot();
    if (!e) return NULL;
    e->block_num = bnum;
    e->dirty = 0;
    if (ReadSector(bnum, e->data) == ERROR) { e->block_num = -1; return NULL; }
    blk_lru_push_front(e);
    return e->data;
}

static void mark_block_dirty(int bnum) {
    struct blk_entry *e = blk_find(bnum);
    if (e) e->dirty = 1;
}

/* ================================================================== */
/* Inode cache helpers                                                  */
/* ================================================================== */

static int block_of_inode(int inum) { return 1 + inum / INODES_PER_BLOCK; }
static int offset_of_inode(int inum) { return (inum % INODES_PER_BLOCK) * INODESIZE; }

static void ino_lru_remove(struct ino_entry *e) {
    if (e->lru_prev) e->lru_prev->lru_next = e->lru_next;
    else             ino_lru_head = e->lru_next;
    if (e->lru_next) e->lru_next->lru_prev = e->lru_prev;
    else             ino_lru_tail = e->lru_prev;
    e->lru_prev = e->lru_next = NULL;
}

static void ino_lru_push_front(struct ino_entry *e) {
    e->lru_prev = NULL;
    e->lru_next = ino_lru_head;
    if (ino_lru_head) ino_lru_head->lru_prev = e;
    else              ino_lru_tail = e;
    ino_lru_head = e;
}

static void ino_lru_move_front(struct ino_entry *e) {
    if (e != ino_lru_head) {
        ino_lru_remove(e);
        ino_lru_push_front(e);
    }
}

static struct ino_entry *ino_find(int inum) {
    int i;
    for (i = 0; i < INODE_CACHESIZE; i++)
        if (ino_cache[i].inum == inum)
            return &ino_cache[i];
    return NULL;
}

/* Write dirty inode into the block cache (not directly to disk). */
static void flush_inode_to_block_cache(struct ino_entry *e) {
    int bnum   = block_of_inode(e->inum);
    int off    = offset_of_inode(e->inum);
    char *blk  = get_block(bnum);
    if (!blk) return;
    memcpy(blk + off, &e->inode, INODESIZE);
    mark_block_dirty(bnum);
}

static struct ino_entry *ino_evict(void) {
    struct ino_entry *e = ino_lru_tail;
    if (!e) return NULL;
    if (e->dirty) { flush_inode_to_block_cache(e); e->dirty = 0; }
    ino_lru_remove(e);
    e->inum = -1;
    return e;
}

static struct ino_entry *ino_free_slot(void) {
    int i;
    for (i = 0; i < INODE_CACHESIZE; i++)
        if (ino_cache[i].inum == -1)
            return &ino_cache[i];
    return ino_evict();
}

/* Returns pointer to inode in cache (or NULL). */
static struct inode *get_inode(int inum) {
    struct ino_entry *e;
    int bnum, off;
    char *blk;

    if (inum <= 0 || inum > g_num_inodes) return NULL;
    e = ino_find(inum);
    if (e) { ino_lru_move_front(e); return &e->inode; }

    e = ino_free_slot();
    if (!e) return NULL;
    bnum = block_of_inode(inum);
    off  = offset_of_inode(inum);
    blk  = get_block(bnum);
    if (!blk) return NULL;
    e->inum  = inum;
    e->dirty = 0;
    memcpy(&e->inode, blk + off, INODESIZE);
    ino_lru_push_front(e);
    return &e->inode;
}

static void mark_inode_dirty(int inum) {
    struct ino_entry *e = ino_find(inum);
    if (e) e->dirty = 1;
}

/* ================================================================== */
/* Cache init + sync                                                    */
/* ================================================================== */

static void init_caches(void) {
    int i;
    for (i = 0; i < BLOCK_CACHESIZE; i++) {
        blk_cache[i].block_num = -1;
        blk_cache[i].dirty     = 0;
        blk_cache[i].lru_prev  = NULL;
        blk_cache[i].lru_next  = NULL;
    }
    blk_lru_head = blk_lru_tail = NULL;

    for (i = 0; i < INODE_CACHESIZE; i++) {
        ino_cache[i].inum     = -1;
        ino_cache[i].dirty    = 0;
        ino_cache[i].lru_prev = NULL;
        ino_cache[i].lru_next = NULL;
    }
    ino_lru_head = ino_lru_tail = NULL;
}

static void sync_all(void) {
    int i;
    /* Flush dirty inodes into block cache first */
    for (i = 0; i < INODE_CACHESIZE; i++)
        if (ino_cache[i].inum != -1 && ino_cache[i].dirty) {
            flush_inode_to_block_cache(&ino_cache[i]);
            ino_cache[i].dirty = 0;
        }
    /* Write dirty blocks to disk */
    for (i = 0; i < BLOCK_CACHESIZE; i++)
        if (blk_cache[i].block_num != -1 && blk_cache[i].dirty) {
            WriteSector(blk_cache[i].block_num, blk_cache[i].data);
            blk_cache[i].dirty = 0;
        }
}

/* ================================================================== */
/* Free list management                                                 */
/* ================================================================== */

static void build_free_lists(void) {
    int i;
    char *used = (char *)calloc(g_num_blocks + 1, 1);
    if (!used) { TracePrintf(0, "YFS: OOM in build_free_lists\n"); Exit(1); }

    free_inode_cnt = 0;
    free_block_cnt = 0;

    for (i = 1; i <= g_num_inodes; i++) {
        struct inode *in = get_inode(i);
        if (!in) continue;
        if (in->type == INODE_FREE) {
            if (free_inode_cnt < MAX_INODE_NUM)
                free_inodes[free_inode_cnt++] = i;
        } else {
            int j;
            for (j = 0; j < NUM_DIRECT; j++)
                if (in->direct[j] > 0 && in->direct[j] < g_num_blocks)
                    used[in->direct[j]] = 1;
            if (in->indirect > 0 && in->indirect < g_num_blocks) {
                int k;
                int *ind;
                used[in->indirect] = 1;
                ind = (int *)get_block(in->indirect);
                if (ind)
                    for (k = 0; k < INDIR_ENTRIES; k++)
                        if (ind[k] > 0 && ind[k] < g_num_blocks)
                            used[ind[k]] = 1;
            }
        }
    }

    for (i = g_first_data_block; i < g_num_blocks; i++)
        if (!used[i] && free_block_cnt < MAX_BLOCK_NUM)
            free_blocks[free_block_cnt++] = i;

    free(used);
    TracePrintf(1, "YFS: %d free inodes, %d free blocks\n",
                free_inode_cnt, free_block_cnt);
}

/* Allocate a free inode; returns inum > 0 or -1 on failure. */
static int alloc_inode(short type) {
    struct inode *in;
    int inum;
    if (free_inode_cnt == 0) return -1;
    inum = free_inodes[--free_inode_cnt];
    in = get_inode(inum);
    if (!in) { free_inodes[free_inode_cnt++] = inum; return -1; }
    in->reuse++;
    in->type    = type;
    in->nlink   = 0;
    in->size    = 0;
    memset(in->direct, 0, sizeof(in->direct));
    in->indirect = 0;
    mark_inode_dirty(inum);
    return inum;
}

/* Return inode to free list (sets type = INODE_FREE). */
static void release_inode(int inum) {
    struct inode *in = get_inode(inum);
    if (in) { in->type = INODE_FREE; mark_inode_dirty(inum); }
    if (free_inode_cnt < MAX_INODE_NUM)
        free_inodes[free_inode_cnt++] = inum;
}

/* Allocate a free data block (zeroed); returns block_num > 0 or -1. */
static int alloc_block(void) {
    char *blk;
    int bnum;
    if (free_block_cnt == 0) return -1;
    bnum = free_blocks[--free_block_cnt];
    blk  = get_block(bnum);
    if (blk) { memset(blk, 0, BLOCKSIZE); mark_block_dirty(bnum); }
    return bnum;
}

/* Return data block to free list and invalidate in cache. */
static void release_block(int bnum) {
    struct blk_entry *e;
    if (bnum <= 0) return;
    e = blk_find(bnum);
    if (e) { e->dirty = 0; blk_lru_remove(e); e->block_num = -1; }
    if (free_block_cnt < MAX_BLOCK_NUM)
        free_blocks[free_block_cnt++] = bnum;
}

/* ================================================================== */
/* File block helpers                                                   */
/* ================================================================== */

/*
 * Return the disk block number for block index block_idx in the file
 * described by inode inum.
 *
 * allocate=1: allocate a new block (and indirect block) if missing.
 * allocate=0: return 0 for a hole, -1 for error.
 */
static int get_file_block(int inum, int block_idx, int allocate) {
    struct inode *in;
    int indir_bnum, b;
    int *indir;

    if (block_idx < 0) return -1;
    in = get_inode(inum);
    if (!in) return -1;

    if (block_idx < NUM_DIRECT) {
        if (in->direct[block_idx] == 0) {
            if (!allocate) return 0;
            b = alloc_block();
            if (b < 0) return -1;
            /* Re-fetch inode (alloc_block may have flushed cache) */
            in = get_inode(inum);
            if (!in) { release_block(b); return -1; }
            in->direct[block_idx] = b;
            mark_inode_dirty(inum);
            return b;
        }
        return in->direct[block_idx];
    }

    /* Indirect region */
    {
        int indir_idx = block_idx - NUM_DIRECT;
        if (indir_idx >= INDIR_ENTRIES) return -1;  /* beyond max file size */

        if (in->indirect == 0) {
            if (!allocate) return 0;
            b = alloc_block();
            if (b < 0) return -1;
            in = get_inode(inum);
            if (!in) { release_block(b); return -1; }
            in->indirect = b;
            mark_inode_dirty(inum);
        }

        indir_bnum = in->indirect;
        indir = (int *)get_block(indir_bnum);
        if (!indir) return -1;

        if (indir[indir_idx] == 0) {
            if (!allocate) return 0;
            b = alloc_block();
            if (b < 0) return -1;
            /* Re-fetch indirect block (alloc_block may have evicted it) */
            indir = (int *)get_block(indir_bnum);
            if (!indir) { release_block(b); return -1; }
            indir[indir_idx] = b;
            mark_block_dirty(indir_bnum);
            return b;
        }
        return indir[indir_idx];
    }
}

/* Free all data blocks belonging to a file (both direct and indirect). */
static void free_file_blocks(int inum) {
    struct inode *in = get_inode(inum);
    int i;
    if (!in) return;

    for (i = 0; i < NUM_DIRECT; i++) {
        if (in->direct[i] > 0) { release_block(in->direct[i]); in->direct[i] = 0; }
    }
    if (in->indirect > 0) {
        int *indir = (int *)get_block(in->indirect);
        if (indir) {
            for (i = 0; i < INDIR_ENTRIES; i++)
                if (indir[i] > 0) release_block(indir[i]);
        }
        release_block(in->indirect);
        in->indirect = 0;
    }
    in->size = 0;
    mark_inode_dirty(inum);
}

/* ================================================================== */
/* Directory helpers                                                    */
/* ================================================================== */

/*
 * Look up name (length namelen, not null-terminated) in directory dir_inum.
 * Returns inode number if found, -1 if not found, ERROR on error.
 */
static int dir_lookup(int dir_inum, const char *name, int namelen) {
    struct inode *in;
    int pos, size;

    if (namelen <= 0 || namelen > DIRNAMELEN) return ERROR;
    in = get_inode(dir_inum);
    if (!in || in->type != INODE_DIRECTORY) return ERROR;

    size = in->size;
    for (pos = 0; pos < size; pos += (int)sizeof(struct dir_entry)) {
        int bidx    = pos / BLOCKSIZE;
        int boff    = pos % BLOCKSIZE;
        int bnum    = get_file_block(dir_inum, bidx, 0);
        char *blk;
        struct dir_entry *de;
        int j, match;

        if (bnum == 0) continue;   /* hole */
        if (bnum < 0)  return ERROR;
        blk = get_block(bnum);
        if (!blk) return ERROR;
        de  = (struct dir_entry *)(blk + boff);
        if (de->inum == 0) continue;

        match = 1;
        for (j = 0; j < namelen; j++) {
            if (de->name[j] != name[j]) { match = 0; break; }
        }
        if (match && (namelen == DIRNAMELEN || de->name[namelen] == '\0'))
            return de->inum;
    }
    return NOT_FOUND;  /* entry not found */
}

/*
 * Add an entry (entry_inum, name[namelen]) to directory dir_inum.
 * Reuses first free slot or appends.  Returns 0 or ERROR.
 */
static int dir_add_entry(int dir_inum, int entry_inum, const char *name, int namelen) {
    struct inode *in;
    int pos, size;

    if (namelen <= 0 || namelen > DIRNAMELEN) return ERROR;
    in = get_inode(dir_inum);
    if (!in || in->type != INODE_DIRECTORY) return ERROR;

    size = in->size;
    /* Scan for a free slot */
    for (pos = 0; pos < size; pos += (int)sizeof(struct dir_entry)) {
        int bidx = pos / BLOCKSIZE;
        int boff = pos % BLOCKSIZE;
        int bnum = get_file_block(dir_inum, bidx, 0);
        char *blk;
        struct dir_entry *de;

        if (bnum <= 0) continue;
        blk = get_block(bnum);
        if (!blk) return ERROR;
        de  = (struct dir_entry *)(blk + boff);
        if (de->inum == 0) {
            de->inum = (short)entry_inum;
            memset(de->name, 0, DIRNAMELEN);
            memcpy(de->name, name, namelen);
            mark_block_dirty(bnum);
            return 0;
        }
    }

    /* Append */
    {
        int new_pos = size;
        int bidx    = new_pos / BLOCKSIZE;
        int boff    = new_pos % BLOCKSIZE;
        int bnum    = get_file_block(dir_inum, bidx, 1);
        char *blk;
        struct dir_entry *de;

        if (bnum <= 0) return ERROR;
        blk = get_block(bnum);
        if (!blk) return ERROR;
        de  = (struct dir_entry *)(blk + boff);
        de->inum = (short)entry_inum;
        memset(de->name, 0, DIRNAMELEN);
        memcpy(de->name, name, namelen);
        mark_block_dirty(bnum);

        /* Update directory size */
        in = get_inode(dir_inum);
        if (!in) return ERROR;
        in->size += (int)sizeof(struct dir_entry);
        mark_inode_dirty(dir_inum);
    }
    return 0;
}

/*
 * Remove entry with name[namelen] from directory dir_inum.
 * Returns 0 or ERROR (if not found).
 */
static int dir_remove_entry(int dir_inum, const char *name, int namelen) {
    struct inode *in;
    int pos, size;

    if (namelen <= 0 || namelen > DIRNAMELEN) return ERROR;
    in = get_inode(dir_inum);
    if (!in || in->type != INODE_DIRECTORY) return ERROR;

    size = in->size;
    for (pos = 0; pos < size; pos += (int)sizeof(struct dir_entry)) {
        int bidx = pos / BLOCKSIZE;
        int boff = pos % BLOCKSIZE;
        int bnum = get_file_block(dir_inum, bidx, 0);
        char *blk;
        struct dir_entry *de;
        int j, match;

        if (bnum <= 0) continue;
        blk = get_block(bnum);
        if (!blk) return ERROR;
        de  = (struct dir_entry *)(blk + boff);
        if (de->inum == 0) continue;

        match = 1;
        for (j = 0; j < namelen; j++) {
            if (de->name[j] != name[j]) { match = 0; break; }
        }
        if (match && (namelen == DIRNAMELEN || de->name[namelen] == '\0')) {
            de->inum = 0;
            memset(de->name, 0, DIRNAMELEN);
            mark_block_dirty(bnum);
            return 0;
        }
    }
    return ERROR;
}

/* ================================================================== */
/* Pathname lookup                                                       */
/* ================================================================== */

/*
 * Resolve pathname starting from cwd_inum.
 * follow_last: 1 = follow symlink if last component is one.
 * parent_inum: set to parent directory inum (or -1).
 * last_name / last_namelen: set to last path component.
 *
 * Returns:
 *   > 0  : inode number of found file
 *   -1   : last component not found, but parent exists (used for create)
 *   ERROR: path error or intermediate component missing
 */
static int lookup_path(int cwd_inum, const char *path,
                        int follow_last,
                        int *parent_inum,
                        char *last_name, int *last_namelen,
                        int depth)
{
    const char *p;
    int cur_inum;
    struct inode *cur_in;

    if (!path || path[0] == '\0') return ERROR;
    if (depth > MAXSYMLINKS) return ERROR;

    if (parent_inum)   *parent_inum   = -1;
    if (last_name)      last_name[0]  = '\0';
    if (last_namelen)  *last_namelen  = 0;

    cur_inum = (path[0] == '/') ? ROOTINODE : cwd_inum;

    /* Validate starting inode is a directory */
    cur_in = get_inode(cur_inum);
    if (!cur_in || cur_in->type != INODE_DIRECTORY) return ERROR;

    p = path;
    while (*p == '/') p++;  /* skip leading slashes */

    /* Path was just "/" (or "////") -> return root */
    if (*p == '\0') {
        if (parent_inum)  *parent_inum  = ROOTINODE;
        if (last_name)    { last_name[0] = '.'; last_name[1] = '\0'; }
        if (last_namelen) *last_namelen = 1;
        return cur_inum;
    }

    while (*p != '\0') {
        const char *start = p;
        int complen;
        int is_last;
        int found;

        /* Advance to end of component */
        while (*p != '/' && *p != '\0') p++;
        complen = (int)(p - start);

        /* Skip inter-component slashes; check if this is last component */
        while (*p == '/') p++;
        is_last = (*p == '\0');

        if (complen > DIRNAMELEN) return ERROR;

        /* Dot and dot-dot handled naturally by directory entries */

        if (is_last) {
            /* Record parent info */
            if (parent_inum)  *parent_inum  = cur_inum;
            if (last_name) {
                memcpy(last_name, start, complen);
                last_name[complen] = '\0';
            }
            if (last_namelen) *last_namelen = complen;

            found = dir_lookup(cur_inum, start, complen);
            if (found == ERROR) return ERROR;
            if (found < 0)      return NOT_FOUND;  /* last component not found */

            /* Follow symlink for last component if requested */
            if (follow_last) {
                struct inode *fin = get_inode(found);
                if (!fin) return ERROR;
                if (fin->type == INODE_SYMLINK) {
                    /* Read symlink target */
                    char link_target[MAXPATHNAMELEN];
                    int link_len = fin->size;
                    int bnum;
                    char *blk;
                    int start_inum;

                    if (link_len <= 0 || link_len >= MAXPATHNAMELEN) return ERROR;
                    bnum = get_file_block(found, 0, 0);
                    if (bnum <= 0) return ERROR;
                    blk  = get_block(bnum);
                    if (!blk) return ERROR;
                    memcpy(link_target, blk, link_len);
                    link_target[link_len] = '\0';

                    start_inum = (link_target[0] == '/') ? ROOTINODE : cur_inum;
                    return lookup_path(start_inum, link_target,
                                       follow_last, NULL, NULL, NULL, depth + 1);
                }
            }
            return found;
        }

        /* Intermediate component - must be a directory (or symlink to one) */
        found = dir_lookup(cur_inum, start, complen);
        if (found == ERROR || found < 0) return ERROR;

        {
            struct inode *fin = get_inode(found);
            if (!fin) return ERROR;

            if (fin->type == INODE_SYMLINK) {
                /* Follow symlink for intermediate component */
                char link_target[MAXPATHNAMELEN];
                int link_len = fin->size;
                int bnum;
                char *blk;
                int start_inum;
                int resolved;

                if (link_len <= 0 || link_len >= MAXPATHNAMELEN) return ERROR;
                bnum = get_file_block(found, 0, 0);
                if (bnum <= 0) return ERROR;
                blk  = get_block(bnum);
                if (!blk) return ERROR;
                memcpy(link_target, blk, link_len);
                link_target[link_len] = '\0';

                start_inum = (link_target[0] == '/') ? ROOTINODE : cur_inum;
                resolved = lookup_path(start_inum, link_target,
                                       1, NULL, NULL, NULL, depth + 1);
                if (resolved == ERROR || resolved < 0) return ERROR;
                fin = get_inode(resolved);
                if (!fin) return ERROR;
                found = resolved;
            }

            if (fin->type != INODE_DIRECTORY) return ERROR;
            cur_inum = found;
        }
    }

    return ERROR;  /* shouldn't reach */
}

/* ================================================================== */
/* Reply helpers                                                        */
/* ================================================================== */

static void send_error(int pid) {
    struct msg_reply r;
    memset(&r, 0, sizeof(r));
    r.ret = ERROR;
    Reply(&r, pid);
}

static void send_ok(int pid, int inum, int reuse) {
    struct msg_reply r;
    memset(&r, 0, sizeof(r));
    r.ret   = 0;
    r.inum  = inum;
    r.reuse = reuse;
    Reply(&r, pid);
}

/* ================================================================== */
/* Handler: Open                                                        */
/* ================================================================== */

static void handle_open(int pid, struct msg_path *req) {
    char path[MAXPATHNAMELEN];
    struct inode *in;
    int inum;

    if (req->pathlen <= 0 || req->pathlen > MAXPATHNAMELEN) { send_error(pid); return; }
    if (CopyFrom(pid, path, req->path, req->pathlen) == ERROR) { send_error(pid); return; }
    path[req->pathlen - 1] = '\0';

    inum = lookup_path(req->cwd_inum, path, 1, NULL, NULL, NULL, 0);
    if (inum <= 0) { send_error(pid); return; }  /* ERROR or NOT_FOUND */

    in = get_inode(inum);
    if (!in) { send_error(pid); return; }

    {
        struct msg_reply r;
        memset(&r, 0, sizeof(r));
        r.ret   = 0;
        r.inum  = inum;
        r.reuse = in->reuse;
        Reply(&r, pid);
    }
}

/* ================================================================== */
/* Handler: Create                                                      */
/* ================================================================== */

static void handle_create(int pid, struct msg_path *req) {
    char path[MAXPATHNAMELEN];
    char last_name[DIRNAMELEN + 1];
    int last_namelen, parent_inum, inum;
    struct inode *in;

    if (req->pathlen <= 0 || req->pathlen > MAXPATHNAMELEN) { send_error(pid); return; }
    if (CopyFrom(pid, path, req->path, req->pathlen) == ERROR) { send_error(pid); return; }
    path[req->pathlen - 1] = '\0';

    inum = lookup_path(req->cwd_inum, path, 1,
                       &parent_inum, last_name, &last_namelen, 0);
    /* inum > 0: found; inum == NOT_FOUND (-2): create; inum == ERROR (-1): bail */
    if (inum == ERROR) { send_error(pid); return; }

    if (inum > 0) {
        /* File exists - truncate */
        in = get_inode(inum);
        if (!in) { send_error(pid); return; }
        if (in->type == INODE_DIRECTORY) { send_error(pid); return; }
        free_file_blocks(inum);
        in = get_inode(inum);
        if (!in) { send_error(pid); return; }
        {
            struct msg_reply r;
            memset(&r, 0, sizeof(r));
            r.ret   = 0;
            r.inum  = inum;
            r.reuse = in->reuse;
            Reply(&r, pid);
        }
        return;
    }

    /* File doesn't exist - create */
    if (parent_inum < 0 || last_namelen <= 0) { send_error(pid); return; }

    {
        int new_inum = alloc_inode(INODE_REGULAR);
        if (new_inum < 0) { send_error(pid); return; }

        in = get_inode(new_inum);
        if (!in) { release_inode(new_inum); send_error(pid); return; }
        in->nlink = 1;
        mark_inode_dirty(new_inum);

        if (dir_add_entry(parent_inum, new_inum, last_name, last_namelen) == ERROR) {
            release_inode(new_inum);
            send_error(pid);
            return;
        }

        in = get_inode(new_inum);
        if (!in) { send_error(pid); return; }
        {
            struct msg_reply r;
            memset(&r, 0, sizeof(r));
            r.ret   = 0;
            r.inum  = new_inum;
            r.reuse = in->reuse;
            Reply(&r, pid);
        }
    }
}

/* ================================================================== */
/* Handler: Read                                                        */
/* ================================================================== */

static void handle_read(int pid, struct msg_rw *req) {
    struct inode *in;
    int inum, reuse_exp, pos, size, file_size;
    int bytes_read, cur_pos, remaining;
    char tmp[BLOCKSIZE];

    inum      = req->inum;
    reuse_exp = req->reuse;
    pos       = req->pos;
    size      = req->size;

    if (size < 0) { send_error(pid); return; }
    if (size == 0) { send_ok(pid, 0, 0); return; }

    in = get_inode(inum);
    if (!in || in->type == INODE_FREE || in->reuse != reuse_exp) { send_error(pid); return; }

    file_size = in->size;
    if (pos >= file_size) { send_ok(pid, 0, 0); return; }
    if (pos + size > file_size) size = file_size - pos;

    bytes_read = 0;
    cur_pos    = pos;
    remaining  = size;

    while (remaining > 0) {
        int bidx   = cur_pos / BLOCKSIZE;
        int boff   = cur_pos % BLOCKSIZE;
        int to_rd  = BLOCKSIZE - boff;
        int bnum;
        char *blk;

        if (to_rd > remaining) to_rd = remaining;

        bnum = get_file_block(inum, bidx, 0);
        if (bnum == 0) {
            memset(tmp, 0, to_rd);
        } else if (bnum < 0) {
            break;
        } else {
            blk = get_block(bnum);
            if (!blk) break;
            memcpy(tmp, blk + boff, to_rd);
        }

        if (CopyTo(pid, (char *)req->buf + bytes_read, tmp, to_rd) == ERROR) break;

        bytes_read += to_rd;
        cur_pos    += to_rd;
        remaining  -= to_rd;
    }

    {
        struct msg_reply r;
        memset(&r, 0, sizeof(r));
        r.ret = bytes_read;
        Reply(&r, pid);
    }
}

/* ================================================================== */
/* Handler: Write                                                       */
/* ================================================================== */

static void handle_write(int pid, struct msg_rw *req) {
    struct inode *in;
    int inum, reuse_exp, pos, size;
    int bytes_written, cur_pos, remaining;
    char tmp[BLOCKSIZE];

    inum      = req->inum;
    reuse_exp = req->reuse;
    pos       = req->pos;
    size      = req->size;

    if (size < 0) { send_error(pid); return; }
    if (size == 0) { send_ok(pid, 0, 0); return; }

    in = get_inode(inum);
    if (!in || in->type == INODE_FREE || in->reuse != reuse_exp) { send_error(pid); return; }
    if (in->type == INODE_DIRECTORY) { send_error(pid); return; }

    bytes_written = 0;
    cur_pos       = pos;
    remaining     = size;

    while (remaining > 0) {
        int bidx   = cur_pos / BLOCKSIZE;
        int boff   = cur_pos % BLOCKSIZE;
        int to_wr  = BLOCKSIZE - boff;
        int bnum;
        char *blk;

        if (to_wr > remaining) to_wr = remaining;

        bnum = get_file_block(inum, bidx, 1);
        if (bnum <= 0) break;

        blk = get_block(bnum);
        if (!blk) break;

        if (CopyFrom(pid, tmp, (char *)req->buf + bytes_written, to_wr) == ERROR) break;

        memcpy(blk + boff, tmp, to_wr);
        mark_block_dirty(bnum);

        bytes_written += to_wr;
        cur_pos       += to_wr;
        remaining     -= to_wr;
    }

    /* Update file size if we extended it */
    in = get_inode(inum);
    if (in && cur_pos > in->size) {
        in->size = cur_pos;
        mark_inode_dirty(inum);
    }

    {
        struct msg_reply r;
        memset(&r, 0, sizeof(r));
        r.ret = bytes_written;
        Reply(&r, pid);
    }
}

/* ================================================================== */
/* Handler: Seek                                                        */
/* ================================================================== */

static void handle_seek(int pid, struct msg_seek *req) {
    struct inode *in;
    int new_pos;

    in = get_inode(req->inum);
    if (!in || in->type == INODE_FREE || in->reuse != req->reuse) { send_error(pid); return; }

    switch (req->whence) {
        case SEEK_SET: new_pos = req->offset; break;
        case SEEK_CUR: new_pos = req->pos + req->offset; break;
        case SEEK_END: new_pos = in->size + req->offset; break;
        default: send_error(pid); return;
    }
    if (new_pos < 0) { send_error(pid); return; }

    {
        struct msg_reply r;
        memset(&r, 0, sizeof(r));
        r.ret = new_pos;
        Reply(&r, pid);
    }
}

/* ================================================================== */
/* Handler: Link                                                        */
/* ================================================================== */

static void handle_link(int pid, struct msg_path *req) {
    char oldpath[MAXPATHNAMELEN], newpath[MAXPATHNAMELEN];
    char last_name[DIRNAMELEN + 1];
    int last_namelen, parent_inum;
    struct inode *in;
    int old_inum, new_inum;

    if (req->pathlen  <= 0 || req->pathlen  > MAXPATHNAMELEN) { send_error(pid); return; }
    if (req->pathlen2 <= 0 || req->pathlen2 > MAXPATHNAMELEN) { send_error(pid); return; }
    if (CopyFrom(pid, oldpath, req->path,  req->pathlen)  == ERROR) { send_error(pid); return; }
    if (CopyFrom(pid, newpath, req->path2, req->pathlen2) == ERROR) { send_error(pid); return; }
    oldpath[req->pathlen  - 1] = '\0';
    newpath[req->pathlen2 - 1] = '\0';

    old_inum = lookup_path(req->cwd_inum, oldpath, 0, NULL, NULL, NULL, 0);
    if (old_inum <= 0) { send_error(pid); return; }
    in = get_inode(old_inum);
    if (!in || in->type == INODE_DIRECTORY) { send_error(pid); return; }

    new_inum = lookup_path(req->cwd_inum, newpath, 0, &parent_inum, last_name, &last_namelen, 0);
    if (new_inum != NOT_FOUND) { send_error(pid); return; }  /* already exists or error */
    if (parent_inum < 0 || last_namelen <= 0) { send_error(pid); return; }

    if (dir_add_entry(parent_inum, old_inum, last_name, last_namelen) == ERROR) { send_error(pid); return; }

    in = get_inode(old_inum);
    if (!in) { send_error(pid); return; }
    in->nlink++;
    mark_inode_dirty(old_inum);

    send_ok(pid, 0, 0);
}

/* ================================================================== */
/* Handler: Unlink                                                      */
/* ================================================================== */

static void handle_unlink(int pid, struct msg_path *req) {
    char path[MAXPATHNAMELEN];
    char last_name[DIRNAMELEN + 1];
    int last_namelen, parent_inum, inum;
    struct inode *in;

    if (req->pathlen <= 0 || req->pathlen > MAXPATHNAMELEN) { send_error(pid); return; }
    if (CopyFrom(pid, path, req->path, req->pathlen) == ERROR) { send_error(pid); return; }
    path[req->pathlen - 1] = '\0';

    inum = lookup_path(req->cwd_inum, path, 0, &parent_inum, last_name, &last_namelen, 0);
    if (inum <= 0) { send_error(pid); return; }
    in = get_inode(inum);
    if (!in || in->type == INODE_DIRECTORY) { send_error(pid); return; }

    if (dir_remove_entry(parent_inum, last_name, last_namelen) == ERROR) { send_error(pid); return; }

    in = get_inode(inum);
    if (!in) { send_error(pid); return; }
    in->nlink--;
    if (in->nlink <= 0) {
        free_file_blocks(inum);
        release_inode(inum);
    } else {
        mark_inode_dirty(inum);
    }
    send_ok(pid, 0, 0);
}

/* ================================================================== */
/* Handler: SymLink                                                     */
/* ================================================================== */

static void handle_symlink(int pid, struct msg_path *req) {
    char oldpath[MAXPATHNAMELEN], newpath[MAXPATHNAMELEN];
    char last_name[DIRNAMELEN + 1];
    int last_namelen, parent_inum, new_inum;
    struct inode *sl_in;
    int sl_inum, target_len, bnum;
    char *blk;

    if (req->pathlen  <= 0 || req->pathlen  > MAXPATHNAMELEN) { send_error(pid); return; }
    if (req->pathlen2 <= 0 || req->pathlen2 > MAXPATHNAMELEN) { send_error(pid); return; }
    if (CopyFrom(pid, oldpath, req->path,  req->pathlen)  == ERROR) { send_error(pid); return; }
    if (CopyFrom(pid, newpath, req->path2, req->pathlen2) == ERROR) { send_error(pid); return; }
    oldpath[req->pathlen  - 1] = '\0';
    newpath[req->pathlen2 - 1] = '\0';

    if (oldpath[0] == '\0') { send_error(pid); return; }

    new_inum = lookup_path(req->cwd_inum, newpath, 0, &parent_inum, last_name, &last_namelen, 0);
    if (new_inum != NOT_FOUND) { send_error(pid); return; }
    if (parent_inum < 0 || last_namelen <= 0) { send_error(pid); return; }

    sl_inum = alloc_inode(INODE_SYMLINK);
    if (sl_inum < 0) { send_error(pid); return; }

    sl_in = get_inode(sl_inum);
    if (!sl_in) { release_inode(sl_inum); send_error(pid); return; }
    sl_in->nlink = 1;
    mark_inode_dirty(sl_inum);

    target_len = (int)strlen(oldpath);
    if (target_len > BLOCKSIZE) target_len = BLOCKSIZE;

    bnum = get_file_block(sl_inum, 0, 1);
    if (bnum <= 0) { release_inode(sl_inum); send_error(pid); return; }
    blk = get_block(bnum);
    if (!blk) { free_file_blocks(sl_inum); release_inode(sl_inum); send_error(pid); return; }
    memcpy(blk, oldpath, target_len);
    mark_block_dirty(bnum);

    sl_in = get_inode(sl_inum);
    if (!sl_in) { free_file_blocks(sl_inum); release_inode(sl_inum); send_error(pid); return; }
    sl_in->size = target_len;
    mark_inode_dirty(sl_inum);

    if (dir_add_entry(parent_inum, sl_inum, last_name, last_namelen) == ERROR) {
        free_file_blocks(sl_inum);
        release_inode(sl_inum);
        send_error(pid);
        return;
    }
    send_ok(pid, 0, 0);
}

/* ================================================================== */
/* Handler: ReadLink                                                    */
/* ================================================================== */

static void handle_readlink(int pid, struct msg_path *req) {
    char path[MAXPATHNAMELEN];
    char link_buf[BLOCKSIZE];
    struct inode *in;
    int inum, link_len, buf_len, copy_len, bnum;
    char *blk;

    if (req->pathlen <= 0 || req->pathlen > MAXPATHNAMELEN) { send_error(pid); return; }
    if (CopyFrom(pid, path, req->path, req->pathlen) == ERROR) { send_error(pid); return; }
    path[req->pathlen - 1] = '\0';

    inum = lookup_path(req->cwd_inum, path, 0, NULL, NULL, NULL, 0);
    if (inum <= 0) { send_error(pid); return; }
    in = get_inode(inum);
    if (!in || in->type != INODE_SYMLINK) { send_error(pid); return; }

    link_len = in->size;
    buf_len  = req->pathlen2;
    copy_len = (link_len < buf_len) ? link_len : buf_len;

    if (copy_len > 0) {
        bnum = get_file_block(inum, 0, 0);
        if (bnum <= 0) { send_error(pid); return; }
        blk = get_block(bnum);
        if (!blk) { send_error(pid); return; }
        memcpy(link_buf, blk, copy_len);
        if (CopyTo(pid, req->path2, link_buf, copy_len) == ERROR) { send_error(pid); return; }
    }

    {
        struct msg_reply r;
        memset(&r, 0, sizeof(r));
        r.ret = copy_len;
        Reply(&r, pid);
    }
}

/* ================================================================== */
/* Handler: MkDir                                                       */
/* ================================================================== */

static void handle_mkdir(int pid, struct msg_path *req) {
    char path[MAXPATHNAMELEN];
    char last_name[DIRNAMELEN + 1];
    int last_namelen, parent_inum, inum, new_inum;
    struct inode *new_in, *par_in;

    if (req->pathlen <= 0 || req->pathlen > MAXPATHNAMELEN) { send_error(pid); return; }
    if (CopyFrom(pid, path, req->path, req->pathlen) == ERROR) { send_error(pid); return; }
    path[req->pathlen - 1] = '\0';

    inum = lookup_path(req->cwd_inum, path, 0, &parent_inum, last_name, &last_namelen, 0);
    if (inum != NOT_FOUND) { send_error(pid); return; }  /* exists or error */
    if (parent_inum < 0 || last_namelen <= 0) { send_error(pid); return; }

    new_inum = alloc_inode(INODE_DIRECTORY);
    if (new_inum < 0) { send_error(pid); return; }

    new_in = get_inode(new_inum);
    if (!new_in) { release_inode(new_inum); send_error(pid); return; }
    new_in->nlink = 2;  /* "." + parent entry */
    mark_inode_dirty(new_inum);

    /* Add "." and ".." */
    if (dir_add_entry(new_inum, new_inum, ".", 1) == ERROR) {
        release_inode(new_inum); send_error(pid); return;
    }
    if (dir_add_entry(new_inum, parent_inum, "..", 2) == ERROR) {
        free_file_blocks(new_inum); release_inode(new_inum); send_error(pid); return;
    }
    /* Add entry in parent */
    if (dir_add_entry(parent_inum, new_inum, last_name, last_namelen) == ERROR) {
        free_file_blocks(new_inum); release_inode(new_inum); send_error(pid); return;
    }
    /* Increment parent nlink (new dir's ".." points to parent) */
    par_in = get_inode(parent_inum);
    if (par_in) { par_in->nlink++; mark_inode_dirty(parent_inum); }

    send_ok(pid, 0, 0);
}

/* ================================================================== */
/* Handler: RmDir                                                       */
/* ================================================================== */

static void handle_rmdir(int pid, struct msg_path *req) {
    char path[MAXPATHNAMELEN];
    char last_name[DIRNAMELEN + 1];
    int last_namelen, parent_inum, inum;
    struct inode *in, *par_in;
    int pos, size, non_empty;

    if (req->pathlen <= 0 || req->pathlen > MAXPATHNAMELEN) { send_error(pid); return; }
    if (CopyFrom(pid, path, req->path, req->pathlen) == ERROR) { send_error(pid); return; }
    path[req->pathlen - 1] = '\0';

    inum = lookup_path(req->cwd_inum, path, 0, &parent_inum, last_name, &last_namelen, 0);
    if (inum <= 0) { send_error(pid); return; }
    if (inum == ROOTINODE) { send_error(pid); return; }

    in = get_inode(inum);
    if (!in || in->type != INODE_DIRECTORY) { send_error(pid); return; }

    /* Verify directory is empty (only "." and "..") */
    size      = in->size;
    non_empty = 0;
    for (pos = 0; pos < size && !non_empty; pos += (int)sizeof(struct dir_entry)) {
        int bidx = pos / BLOCKSIZE;
        int boff = pos % BLOCKSIZE;
        int bnum = get_file_block(inum, bidx, 0);
        char *blk;
        struct dir_entry *de;

        if (bnum <= 0) continue;
        blk = get_block(bnum);
        if (!blk) { send_error(pid); return; }
        de  = (struct dir_entry *)(blk + boff);
        if (de->inum == 0) continue;
        /* Check for "." and ".." */
        if (de->name[0] == '.' &&
            (de->name[1] == '\0' ||
             (de->name[1] == '.' && de->name[2] == '\0')))
            continue;
        non_empty = 1;
    }
    if (non_empty) { send_error(pid); return; }

    if (dir_remove_entry(parent_inum, last_name, last_namelen) == ERROR) { send_error(pid); return; }

    par_in = get_inode(parent_inum);
    if (par_in) { par_in->nlink--; mark_inode_dirty(parent_inum); }

    free_file_blocks(inum);
    release_inode(inum);
    send_ok(pid, 0, 0);
}

/* ================================================================== */
/* Handler: ChDir                                                       */
/* ================================================================== */

static void handle_chdir(int pid, struct msg_path *req) {
    char path[MAXPATHNAMELEN];
    struct inode *in;
    int inum;

    if (req->pathlen <= 0 || req->pathlen > MAXPATHNAMELEN) { send_error(pid); return; }
    if (CopyFrom(pid, path, req->path, req->pathlen) == ERROR) { send_error(pid); return; }
    path[req->pathlen - 1] = '\0';

    inum = lookup_path(req->cwd_inum, path, 1, NULL, NULL, NULL, 0);
    if (inum <= 0) { send_error(pid); return; }
    in = get_inode(inum);
    if (!in || in->type != INODE_DIRECTORY) { send_error(pid); return; }

    {
        struct msg_reply r;
        memset(&r, 0, sizeof(r));
        r.ret  = 0;
        r.inum = inum;
        Reply(&r, pid);
    }
}

/* ================================================================== */
/* Handler: Stat                                                        */
/* ================================================================== */

static void handle_stat(int pid, struct msg_path *req) {
    char path[MAXPATHNAMELEN];
    struct inode *in;
    struct Stat st;
    int inum;

    if (req->pathlen <= 0 || req->pathlen > MAXPATHNAMELEN) { send_error(pid); return; }
    if (CopyFrom(pid, path, req->path, req->pathlen) == ERROR) { send_error(pid); return; }
    path[req->pathlen - 1] = '\0';

    inum = lookup_path(req->cwd_inum, path, 0, NULL, NULL, NULL, 0);
    if (inum <= 0) { send_error(pid); return; }
    in = get_inode(inum);
    if (!in) { send_error(pid); return; }

    st.inum  = inum;
    st.type  = in->type;
    st.size  = in->size;
    st.nlink = in->nlink;

    if (CopyTo(pid, req->path2, &st, sizeof(struct Stat)) == ERROR) { send_error(pid); return; }
    send_ok(pid, 0, 0);
}

/* ================================================================== */
/* Handler: Sync / Shutdown                                             */
/* ================================================================== */

static void handle_sync(int pid) {
    sync_all();
    send_ok(pid, 0, 0);
}

static void handle_shutdown(int pid) {
    TracePrintf(0, "YFS: Shutdown requested\n");
    sync_all();
    send_ok(pid, 0, 0);
    Exit(0);
}

/* ================================================================== */
/* main                                                                 */
/* ================================================================== */

int main(int argc, char *argv[]) {
    char msg_buf[32];
    struct fs_header *hdr;
    char *super;

    init_caches();

    /* Read superblock */
    super = get_block(1);
    if (!super) { TracePrintf(0, "YFS: Cannot read superblock\n"); Exit(1); }
    hdr = (struct fs_header *)super;
    g_num_inodes     = hdr->num_blocks;  /* wait, num_blocks field */
    g_num_blocks     = hdr->num_blocks;
    g_num_inodes     = hdr->num_inodes;
    g_first_data_block = 1 + (g_num_inodes + 1 + INODES_PER_BLOCK - 1) / INODES_PER_BLOCK;

    TracePrintf(1, "YFS: num_inodes=%d num_blocks=%d first_data_block=%d\n",
                g_num_inodes, g_num_blocks, g_first_data_block);

    build_free_lists();

    if (Register(FILE_SERVER) == ERROR) {
        TracePrintf(0, "YFS: Register failed\n"); Exit(1);
    }

    if (argc > 1) {
        int pid = Fork();
        if (pid == 0) { Exec(argv[1], argv + 1); Exit(1); }
    }

    /* Main server loop */
    while (1) {
        int sender = Receive(msg_buf);
        if (sender == 0) break;    /* deadlock break - no clients */
        if (sender == ERROR) continue;

        switch (*(int *)msg_buf) {
            case MSG_OPEN:     handle_open    (sender, (struct msg_path *)msg_buf); break;
            case MSG_CREATE:   handle_create  (sender, (struct msg_path *)msg_buf); break;
            case MSG_READ:     handle_read    (sender, (struct msg_rw   *)msg_buf); break;
            case MSG_WRITE:    handle_write   (sender, (struct msg_rw   *)msg_buf); break;
            case MSG_SEEK:     handle_seek    (sender, (struct msg_seek  *)msg_buf); break;
            case MSG_LINK:     handle_link    (sender, (struct msg_path *)msg_buf); break;
            case MSG_UNLINK:   handle_unlink  (sender, (struct msg_path *)msg_buf); break;
            case MSG_SYMLINK:  handle_symlink (sender, (struct msg_path *)msg_buf); break;
            case MSG_READLINK: handle_readlink(sender, (struct msg_path *)msg_buf); break;
            case MSG_MKDIR:    handle_mkdir   (sender, (struct msg_path *)msg_buf); break;
            case MSG_RMDIR:    handle_rmdir   (sender, (struct msg_path *)msg_buf); break;
            case MSG_CHDIR:    handle_chdir   (sender, (struct msg_path *)msg_buf); break;
            case MSG_STAT:     handle_stat    (sender, (struct msg_path *)msg_buf); break;
            case MSG_SYNC:     handle_sync    (sender); break;
            case MSG_SHUTDOWN: handle_shutdown(sender); break;
            default:           send_error(sender); break;
        }
    }

    sync_all();
    TracePrintf(0, "YFS: Exiting\n");
    Exit(0);
    return 0;
}

/*
 * yfs.h - Shared header for YFS server and client library
 *
 * Message structures are exactly 32 bytes (MESSAGE_SIZE).
 */

#ifndef YFS_H
#define YFS_H

/* Seek whence constants (mirrors POSIX values) */
#ifndef SEEK_SET
#define SEEK_SET 0
#define SEEK_CUR 1
#define SEEK_END 2
#endif

/* Message type codes */
#define MSG_OPEN     1
#define MSG_CREATE   2
#define MSG_READ     3
#define MSG_WRITE    4
#define MSG_SEEK     5
#define MSG_LINK     6
#define MSG_UNLINK   7
#define MSG_SYMLINK  8
#define MSG_READLINK 9
#define MSG_MKDIR    10
#define MSG_RMDIR    11
#define MSG_CHDIR    12
#define MSG_STAT     13
#define MSG_SYNC     14
#define MSG_SHUTDOWN 15

/*
 * Message for pathname-based operations.
 * Layout: 4+4+4+4+8+8 = 32 bytes (no padding on 64-bit).
 */
struct msg_path {
    int   type;       /* message type code */
    int   cwd_inum;   /* current directory inode number */
    int   pathlen;    /* length of path1 (includes null byte) */
    int   pathlen2;   /* length of path2 (for Link/SymLink) or buf len (ReadLink) */
    void *path;       /* pointer to pathname in client address space */
    void *path2;      /* second path, statbuf, or readlink result buf in client space */
};

/*
 * Message for Read/Write operations.
 * Layout: 4+4+4+4+8+4+4 = 32 bytes.
 */
struct msg_rw {
    int   type;   /* MSG_READ or MSG_WRITE */
    int   inum;   /* file inode number */
    int   reuse;  /* inode reuse count */
    int   pos;    /* current file position */
    void *buf;    /* pointer to data buffer in client address space */
    int   size;   /* number of bytes to read/write */
    int   pad;
};

/*
 * Message for Seek operation.
 * Layout: 4+4+4+4+4+4+8 = 32 bytes.
 */
struct msg_seek {
    int  type;      /* MSG_SEEK */
    int  inum;      /* file inode number */
    int  reuse;     /* inode reuse count */
    int  pos;       /* current file position */
    int  offset;    /* seek offset */
    int  whence;    /* SEEK_SET, SEEK_CUR, or SEEK_END */
    char pad[8];
};

/*
 * Reply message (server -> client).
 * Layout: 4+4+4+20 = 32 bytes.
 */
struct msg_reply {
    int  ret;    /* return value (bytes read/written, new pos, 0, or ERROR) */
    int  inum;   /* inode number (for Open/Create/ChDir) */
    int  reuse;  /* reuse count (for Open/Create) */
    char pad[20];
};

/*
 * Simple message (Sync, Shutdown).
 * Layout: 4+28 = 32 bytes.
 */
struct msg_simple {
    int  type;
    char pad[28];
};

#endif /* YFS_H */

